INSERT INTO topics (id, lang, category, title, question, answer, objections, scripture, tags, difficulty, related_topics, translation_source, last_updated)
VALUES ('confession-to-priest', 'ceb', 'sacraments', 'Pagkompisal sa Pari', 'Unsa ang gitudlo sa Simbahang Katoliko bahin sa pagkompisal sa pari?', '"Ang Sta. Iglesya nagtudlo nga si Cristo nagtukod sa sacramento sa pagkompisal aron ang sala nga nahimo human sa bunyag mapasaylo pinaagi sa absolusyon nga ihatag sa pari. Ang Sta. Iglesya nagtudlo pa gayod nga gikinahanglan ang pagkompisal sa mga dagko “mortal” nga sala. Ang mga gagmayng sala mahimo nga mapasaylo gawas sa kompisalan pinaagi sa paghimo’g paghinulsol apan makaayo usab ang pagsugid bisan sa gagmayng mga sala. Ang Sta. Iglesya nagsugo nga ang matuohon kinahanglan nga mokompisal labing menos kausa sa usa ka tuig labi na panahon sa kuwaresma.\n\nSi Cristo mianhi sa kalibotan aron pagpasig-uli sa mga makasasala ngadto sa Dios ug aron ang tawo magpuyo diha sa grasya ug makabaton sa kinabuhing dayon. Ang anghel mipahibalo ni Jose, “nganli siyag Jesus- kay luwason niya ang iyang katawhan sa ilang mga sala” (Mat. 1:21). Si Jesus miingon, “Kay wala ako moanhi aron pagtawag sa mga matarong, kondili sa mga makasasala” (Mat. 9:13). Sa dinhi pa siya sa kalibotan si Jesus nagpasaylog sala. Siya miingon sa paralitiko, “Anak, gipasaylo na ang imong mga sala” (Mar. 2:5). Aron pagpadayon sa iyang buluhaton si Jesus nagpili og mga tawo nga iyang gihatagan sa kagahoman sa pagpanudlo, sa pagbalaan ug sa pagdumala sa iyang panon (Mat. 28:20). Gitugyan ni Jesus ang iyang misyon ngadto kanila, “Ingon nga gipadala ako sa Amahan, ako usab nagpadala kaninyo” (Jn. 20:21). Ug kini sila gisul-oban ni Jesus sa gahom sa pagpasaylog sala, “Dawata ninyo ang Espiritu Santo. Kon pasayloon ninyo ang mga sala sa mga tawo, gipasaylo kini; kon ang ilang mga sala dili ninyo pasayloon, dili usab kini pasayloon” (Jn. 20:22-23). Ang maong gahom sa pagpasaylog sala dili usa ka personal nga gasa o charisma kondili usa ka gahom o katungdanan nga gibutang ni Jesus sa Iyang Iglesya busa ang maong ministeryo nahipasa usab ngadto sa mga sumusunod sa mga Apostoles nga mao ang mga kaobispohan ug mga kaparian.\n\nAng pagsugid sa sala ngadto sa pinadala sa Dios usa ka naandang bulohaton sa katawhan sa Dios isip timaan sa ilang paghinulsol. Ang Dios nagsugo, “Magsugid sila sa ilang mga sala nga nahimo” (Num. 5:7). Si Josue miingon kang Acan, “Anak ko, isugid ang kamatuoran dinhi sa atubangan sa Ginoo… ug tug-ani ako sa gibuhat mo. Ayaw kini itago gikan kanako” (Jos. 7:19). Si Saul misugid sa iyang sala ngadto ni Samuel, “Nakasala ako kay gilapas ko man ang imong mga pulong… Busa karon hangyoon ko ikaw nga imo akong pasayloon” (1 Sam. 15:24-25). Si David miingon kang Nathan, ‘Nakasala ako sa Ginoo’. Ug giingnan ni Natan si David, “Gipasaylo usab sa Ginoo ang imong sala…” (2 Sam. 12:13-14). Sa basahon sa Ecclesiastes gihatagan kitag tambag unsaon sa pagbatog kalinaw ug paglikay sa kasuko sa Dios, “Ayaw itugot nga ang imong mga pulong makaangin kanimo sa pagpakasala; busa isugid sa pari sa Dios nga dili mo tuyo ang pagbuhat sa ingon” (Eccl. 5:6). Diha sa Bag-ong Tugon ang katawhan misugid sa ilang mga sala ngadto ni Juan Bautista, “Gisugid nila ang ilang mga sala..” (Mat. 3:6). Dunay mga tawo nga misugid sa ilang mga sala ngadto sa mga Apostoles, “Daghang mga magtutuo nangabot ug sa dayag misugid nga nagsalamangka sila kaniadto” (Buh. 19:18).\n\nMaayo nga atong hisgotan ang kaayohan nga atong madawat gikan niining maong sacramento. Sa pagtukod ni Cristo niini iyang gitubag ang usa ka tawhanong panginahanglan. Nasayod siya nga kitang tawo mangita gayod og timaan nga nadawat na nato ang pasaylo nga atong gitinguha ug kining maong timaan iyang gihatag kanato diha sa kompisalan pinaagi sa absolusyon nga ihatag sa pari. Buot usab kitang ilikay ni Cristo gikan sa atong tawhanong kahuyang. Kon kinahanglan una nga susihon nato ang atong konsensya ug atong hinumdoman sa tinagsatagsa ang mga sala nga atong nahimo, kapila ka higayon nato kini mabuhat ug ang mga sirkumstansya nga makapagrabi niini malikay kita sa taphaw lamang nga paghinulsol. Pinaagi sa kakinahanglanon sa pagsugid sa atong mga sala ngadto sa pari gitudloan kita ni Cristo sa pagpaubos. Tungod sa atong garbo buot natong tagoan ang atong mga sala ug mangita kitag mga katarungan nga mopagaan sa atong mga sala, apan diha sa kompisalan kinahanglan nga atong angkonon ang atong mga sala sa walay lipod-lipod ug pinaagi niini atong mabuntog ang atong garbo. Sa atong pagsugid ngadto sa pari makadawat kita sa maayong pagtambag ug matabangan kita sa pagkab-ot sa mas dako nga kasubo tungod sa atong mga sala ug sa mga paagi sa paglikay niini. Diha sa pagkompisal atong madawat ang diosnong pasaylo ug tungod niini malikay kita sa silot sa impyerno nga alang sa mga dagkong sala. Labaw sa tanan makadawat kita og dugang grasya nga atong gikinahanglan sa pagpuyo sa kinabuhi nga kristohanon. Diha sa pagkompisal atong masinati ang gugma ug ang kaluoy sa Dios nga modawat kanato pag-usab isip iyang pinanggang anak.\n\nAron atong madawat ang mga bunga niining maong sacramento kinahanglan ang paghimo sa maayong nga pagkompisal nga mao kining mosunod: Una- pagsusi sa konsensya, “Susiha ug hukmi ang inyong kaugalingon aron pagtino kon nagpadayon ba kamo sa pagtuo” (2 Cor. 13:5). Ikaduha – ang paghinulsol nga mao ang kasubo nga atong bation gumikan sa sala, “Kay ang kasubo nga gikan sa Dios makapahinulsol ug makatultol kaninyo ngadto sa kaluwasan” (2 Cor. 7:10). Ikatulo- ang pagsugid sa sala ngadto sa pari, “Kadtong nagatabon sa iyang sala dili mouswag apan kadtong nagasugid sa iyang mga sala makadawat og kaluoy” (Prob. 28:13). Ikaupat – ang paglikay sa okasyon kun kahigayonan sa pagpakasala nga mahimo nga tawo, butang o dapit. “Ang maalamon maglikay sa peligro apan ang buangbuang magpaduol hinuon niini” (Prob. 14:16). Ikalima- ang pagpenitensya isip timaan nga andam na kita nga mobuhat sa kabubut-on sa Dios, “Apan bisan karon, paghinulsol kamo sa kinasingkasing ug balik kanako nga magpuasa, maghilak ug magbangotan” (Joel 2:12).\n\nAtong pasalamatan ang Dios sa paghatag kanato niining maong sacramento. Atong pangayoon kaniya ang higayon nga makahimo kita og maayo nga pagkompisal labi sa higayon nga makahimo kitag og mortal nga sala. Dili nato ikaulaw ang pagsugid sa atong mga sala ngadto sa pari aron iya kitang mahatagan sa maayong pagtambag. Tapos nato madawat ang diosnong pasaylo diha sa kompisalan atong pasalamatan ang Dios ug magtapat kita nga malig-on sa dili na pagpakasala pag-usab."'::jsonb, '[{"objection":"Ang sala adto isugid direkta sa Dios ug dili na kinahanglan nga ipaagi sa pari, “Busa isugid ang inyong mga sala ngadto sa Ginoo” (Esd. 10:11).","response":"Sa Daang Tugon wala pa tukora ni Jesus ang sacramento sa pagkompisal busa ang mga tawo nga makahimog dagkong sala mapasaylo pinaagi sa ilang paghinulsol (Eze. 18:21-23). Apan ang hingpit nga pagpadayag sa Dios sa iyang kaugalingon iyang gihimo pinaagi ni Jesus nga nagtukod niining maong sacramento sa iyang pag-abot diha sa Bag-ong Tugon (Jn. 20:22-23)."},{"objection":"Si David nga miderekta sa Dios napasaylo, “Gisugid ko kini sa Ginoo ug gipasaylo niya ang tanan kong kalapasan” (Sal. 32:5).","response":"Ang gipasabot dinhi mao ang pag-angkon ni David nga siya nakasala atubangan sa Ginoo apan dili sabton nga ang Dios atong sugiran sa tinagsatagsa sa atong mga sala “kay ang tanan natong kasal-anan wala matago gikan kaniya” (Sal. 69:5). Ang tinagsatagsa nga pagsugid sa sala adto itug-an sa iyang mga piniyalan (2 Sam. 12:12-14)."},{"objection":"Si San Juan miingon, “Apan kon isugid nato sa Dios ang atong mga sala, tumanon niya ang iyang mga saad ug buhaton ang matarong ug mopasaylo gayod sa tanan tang mga sala ug maghinlo sa tanan tang mga kalapasan” (1 Jn. 1:9). Busa direkta ngadto sa Dios ang pagsugid.","response":"Wala kini magpasabot nga modiretso na lag kompisal ngadto sa Dios tungod kay kon ingon niana mahimong walay kapuslanan ang gahom sa pagpasaylog sala sa mga tawo nga gihatag ni Cristo ngadto sa iyang mga apostoles (Jn. 20:22-23)."},{"objection":"Si Jesus miingon, “Umari kamo kanako, kamong tanan nga gikapuyan” (Mat. 11:28). Wala siya moingon nga moadto sa pari.","response":"Ang atong pagduol kang Jesus nagpasabot sa atong pagkaandam nga motuman sa iyang paagi (Mat. 7:21). Ang sugo ni Cristo sa pagduol ngadto sa pari nalakip na sa iyang paghatag kanila sa gahom sa pagpasaylog sala tungod kay dayag na lang nga ang mga sala nga kahatagan nilag pasaylo mao lamang kadtong nasugid diha sa pagkompisal."},{"objection":"Giingon usab, “Walay tawo nga makapasaylog sala, kondili ang Dios lamang” (Mar. 2:7). Busa tungod kay ang pari tawo man dili diay makapasaylog sala.","response":"Tinuod kana ang Dios lamang ang makapasaylog sala isip maoy tinubdan sa pasaylo apan dili kita makapugong sa Dios kon ang maong gahom iyang itugyan ngadto sa iyang mga pinadala (Jn.20:21-23). Si San Pablo miingon, “si Cristo naghatag kanamo niining bulohaton sa pagpasig-uli” (2 Cor. 5:18)."},{"objection":"Ang pari makasasala usab ug kadtong hugaw dili makahinlo, “Unsaon mo man pag-ingon sa imong isigkatawo, ‘Abi, kuhaon ko kanang imong puling,’ nga naa may troso sa imong mata?” (Mat. 7:4).","response":"Ang gitudlo ni Cristo dinhi mao ang dili paghukom sa atong isigkatawo o ang dili paghunahuna nga labaw kita kabalaan kay kanila. Ang gahom sa pagpasaylog sala wala mag-agad sa katakos sa pari kondili sa mga pulong ni Cristo, “Kon pasayloon ninyo ang mga sala sa mga tawo, gipasaylo kini…” (Jn. 20:22-23)."},{"objection":"Kanang giingon sa Jn. 20:22-23 dili kana gahom sa pagpasaylo kondili sama kana sa giingon ni Jesus, “pagpinasayloay kamo aron pasayloon kamo sa inyong Amahan nga atua sa langit” (Mat. 18:35).","response":"Dakog kalainan. Ang gihisgotan ni Jesus diha sa Mat. 18:35 mao ang atong katungdanan sa pagpasaylo sa usag-usa isip kondisyon aron ang Dios mopasaylo sa atong mga sala nga iyang gitumong alang sa tanan. Diha sa Jn. 20:22-23 maklaro nato nga gahom kini sa pagpasaylo ug sa dili pagpasaylo sa mga sala sa mga tawo nga gihatag ni Jesus ngadto sa iyang mga apostoles ug niadtong mopuli sa ilang katungdanan."},{"objection":"Ang mga apostoles wala sugoa ni Jesus aron sila mamasaylog sala kondili sa pagsangyaw sa kapasayloan sa sala niadtong maghinulsol ug motuo (Luc. 24:47).","response":"Dili mahitabo nga si Jesus mohatag sa iyang mga apostoles sa gahom sa pagpasaylog sala kon maoy iyang kabubut-on nga dili kini nila gamiton o dili ba kaha sa naandan nga paagi ang tawo makadawat sa iyang pasaylo kon sila modirekta ngadto kaniya. Ang pagsangyaw mahitungod sa kapasayloan sa sala naglangkob niadtong gihimo nga pagtubos ni Cristo kanato pinaagi sa iyang kamatayon didto sa krus ug sa iyang paghatag sa gahom sa pagpasaylog sala ngadto sa iyang mga apostoles human siya mabanhaw!"}]'::jsonb, '["Mat. 1:21","Mat. 9:13","Mar. 2:5","Jn. 20:21","Jn. 20:22-23","Num. 5:7","Jos. 7:19","1 Sam. 15:24-25","2 Sam. 12:13-14","Eccl. 5:6","Mat. 3:6","Buh. 19:18","2 Cor. 13:5","2 Cor. 7:10","Prob. 28:13","Prob. 14:16","Joel 2:12","Esd. 10:11","Sal. 32:5","Sal. 69:5","1 Jn. 1:9","Mat. 11:28","Mar. 2:7","2 Cor. 5:18","Mat. 7:4","Mat. 18:35"]'::jsonb, '["confession to priest"]'::jsonb, 'beginner', '[]'::jsonb, 'manual', '2026-07-23T08:13:34.046Z')
